// ─── Helpers ─────────────────────────────────────────────

export function getTileByIdKey(idKey: number): TileType | undefined {
  return tileTypes.find((t) => t.idKey === idKey);
}

export function getTileByName(name: string): TileType | undefined {
  return tileTypes.find((t) => t.name === name);
}

export function getUnitByIdKey(idKey: number): UnitType | undefined {
  return unitTypes.find((u) => u.idKey === idKey);
}

export function getMergeOutput(tile1: string, tile2: string, tile3: string): string | null {
  const sorted = [tile1, tile2, tile3].sort();
  for (const m of mergeTypes) {
    const ms = [m.firstTileTypeId, m.secondTileTypeId, m.thirdTileTypeId].sort();
    if (sorted[0] === ms[0] && sorted[1] === ms[1] && sorted[2] === ms[2]) {
      return m.outputTileTypeId;
    }
  }
  return null;
}

export function getScaling(level: number) {
  return scalingValues.find((s) => s.level === level) ?? { level, playerStatScale: 1, monsterStatScale: 1 };
}

export function getTriggerName(id: number): string {
  return TriggerTypeNames[id] ?? "Unknown";
}
